parameters.jsCode:
// Verify webhook secret if configured
const secret = $env.N8N_WEBHOOK_SECRET;
if (secret) {
  const receivedSecret = $input.headers['x-webhook-secret'];
  if (receivedSecret !== secret) {
    return [{ json: { error: 'Unauthorized' } }];
  }
}

// Extract body data
const body = $input.body;

// Convert arrays to comma-separated strings for Google Sheets
const formatArray = (arr) => {
  if (!arr || !Array.isArray(arr)) return '';
  return arr.join(', ');
};

// Determine qualification tag based on budget
let qualificationTag = '';
if (body.budget === 'Under $3,000') {
  qualificationTag = 'low-budget';
}

return [{
  json: {
    ...body,
    desiredFeelings: formatArray(body.desiredFeelings),
    styleWords: formatArray(body.styleWords),
    neededPages: formatArray(body.neededPages),
    qualificationTag
  }
}];

// Build the low-budget email subject prefix
const subjectPrefix = $json.qualificationTag === 'low-budget' ? '[LOW BUDGET] ' : '';

// Format fields for André's email
const budget = $json.budget || 'Not specified';
const timeline = $json.timeline || 'Not specified';
const phone = $json.phone || 'Not provided';

return [{
  json: {
    ...$json,
    subjectPrefix,
    budget,
    timeline,
    phone
  }
}];

